<template><section class="page"><RouterLink to="/invocations">← Invocation History</RouterLink><div v-if="loading">Loading…</div><div v-else-if="!item" class="error">Invocation not found.</div><template v-else><header><div><h2>{{item.promptName}}</h2><p>{{item.promptVersionNumber}} · {{item.provider}} / {{item.modelName}}</p></div><button @click="retry">Retry</button></header><InvocationMetrics :invocation="item"/><article v-if="item.errorMessage" class="card error"><h3>{{item.errorType}}</h3><p>{{item.errorMessage}}</p></article><div class="grid"><article class="card"><h3>Rendered System Prompt</h3><pre>{{item.renderedSystemPrompt||'—'}}</pre><h3>Rendered User Prompt</h3><pre>{{item.renderedUserPrompt||'—'}}</pre></article><article class="card"><h3>Raw Output</h3><pre>{{item.rawOutput||'Output empty'}}</pre><h3>Parsed JSON</h3><pre>{{item.parsedOutput===undefined?'Unavailable':JSON.stringify(item.parsedOutput,null,2)}}</pre></article></div><article class="card"><h3>Variable Values</h3><pre>{{JSON.stringify(item.variableValues,null,2)}}</pre><p>Token source: {{item.tokenUsage.source}} · Cost source: {{item.cost.source}}</p></article></template></section></template>
<script setup lang="ts">import{onMounted,ref,watch}from'vue';import{RouterLink,useRoute,useRouter}from'vue-router';import type{ModelInvocation}from'@prompt-optimizer/core';import{usePromptOpsServices}from'../../services/promptops';import InvocationMetrics from'../../components/promptops/playground/InvocationMetrics.vue';const route=useRoute(),router=useRouter(),services=usePromptOpsServices(),item=ref<ModelInvocation>(),loading=ref(true);const load=async()=>{loading.value=true;item.value=await services.invocationRepository.getById(String(route.params.invocationId));loading.value=false};const retry=()=>item.value&&router.push(`/playground/${item.value.promptId}${item.value.promptVersionId?`/version/${item.value.promptVersionId}`:''}`);onMounted(load);watch(()=>route.params.invocationId,load)</script><style scoped>.page{display:grid;gap:16px}.page>a{color:#2563eb;text-decoration:none}header{display:flex;justify-content:space-between}h2{margin:0}.grid{display:grid;grid-template-columns:1fr 1fr;gap:16px}.card{padding:16px;background:#fff;border:1px solid #e5e7eb;border-radius:10px}.card pre{white-space:pre-wrap;word-break:break-word}.error{color:#b91c1c}button{padding:9px 14px;border:1px solid #cbd5e1;border-radius:7px;background:#fff;cursor:pointer}@media(max-width:800px){.grid{grid-template-columns:1fr}}</style>
